        sourcePath:
          'angular/apps/demo-angular/src/app/features/packages/angular/angular-optimistic-state/pages/optimistic-state-toggle-demo-page/optimistic-state-toggle-demo-page.component.html',
        code: '<demo-page-layout testId="optimistic-state-toggle-page">\n  <demo-navigation-strip\n    demoNavigation\n    testId="optimistic-state-toggle-demo-navigation"\n    [demo]="demo"\n  />\n\n  <article\n    demoIntro\n    class="demo-card demo-card--stack"\n    data-testid="optimistic-state-toggle-controls-card"\n  >\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular Optimistic State</p>\n        <h2>Optimistic toggles with configurable same-target overlap behavior.</h2>\n      </div>\n\n      <div class="optimistic-toolbar">\n        <span class="demo-hint-pill" data-testid="optimistic-state-toggle-status-pill"\n          >Status: {{ featureToggles.status() }}</span\n        >\n        <span class="demo-hint-pill" data-testid="optimistic-state-toggle-policy-pill"\n          >Policy: {{ featureToggles.conflictPolicy() }}</span\n        >\n      </div>\n    </div>\n\n    <p class="demo-card__summary">\n      `optimisticState()` keeps the committed value, optimistic overlay, and same-target overlap\n      policy explicit. Switch policies here to see reject, queue, and replace behavior without\n      hiding rollback behind a cache client.\n    </p>\n\n    <div class="optimistic-controls-grid">\n      <label class="demo-field optimistic-controls-grid__wide">\n        <span>Feature</span>\n        <select\n          class="demo-select"\n          [ngModel]="selectedFeatureId()"\n          data-testid="optimistic-state-toggle-feature-select"\n          (ngModelChange)="updateSelectedFeature($event)"\n        >\n          @for (feature of featureToggles.value(); track feature.id) {\n            <option [value]="feature.id">{{ feature.label }}</option>\n          }\n        </select>\n      </label>\n\n      <label class="demo-field optimistic-controls-grid__wide">\n        <span>Conflict policy</span>\n        <select\n          class="demo-select"\n          [ngModel]="featureToggles.conflictPolicy()"\n          data-testid="optimistic-state-toggle-policy-select"\n          (ngModelChange)="updateConflictPolicy($event)"\n        >\n          @for (option of policyOptions; track option.value) {\n            <option [value]="option.value">{{ option.label }}</option>\n          }\n        </select>\n      </label>\n\n      <button\n        type="button"\n        class="demo-button"\n        data-testid="optimistic-state-toggle-enable"\n        (click)="enableSelected()"\n      >\n        Enable selected feature\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="optimistic-state-toggle-disable"\n        (click)="disableSelected()"\n      >\n        Disable selected feature\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="optimistic-state-toggle-overlap"\n        (click)="runOverlap()"\n      >\n        Trigger overlap\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="optimistic-state-toggle-fail"\n        (click)="failSelected()"\n      >\n        Force failure\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="optimistic-state-toggle-reset"\n        (click)="resetDemo()"\n      >\n        Reset demo\n      </button>\n    </div>\n\n    <p class="demo-card__summary" data-testid="optimistic-state-toggle-policy-detail">\n      {{ policyDetail() }}\n    </p>\n\n    <demo-status-strip\n      testId="optimistic-state-toggle-status-strip"\n      summaryTestId="optimistic-state-toggle-summary"\n      urlTestId="optimistic-state-toggle-current-url"\n      [summary]="statusSummary()"\n      [currentUrl]="currentUrl()"\n    />\n  </article>\n\n  <article\n    demoPrimary\n    class="demo-card demo-card--stack"\n    data-testid="optimistic-state-toggle-render-card"\n  >\n    <div class="optimistic-render-grid">\n      <section class="optimistic-surface" data-testid="optimistic-state-toggle-render-panel">\n        <p class="demo-eyebrow">Outlet rendering</p>\n        <h3>Current optimistic list</h3>\n\n        <hexguard-optimistic-state-outlet\n          [state]="featureToggles"\n          [valueTemplate]="valueTemplate"\n          [pendingTemplate]="pendingTemplate"\n          [errorTemplate]="errorTemplate"\n        />\n\n        <ng-template #pendingTemplate let-entries>\n          <div\n            class="optimistic-callout optimistic-callout--pending"\n            data-testid="optimistic-state-toggle-pending"\n          >\n            {{ entries.length }} mutation is pending under the {{ featureToggles.conflictPolicy() }}\n            policy.\n          </div>\n        </ng-template>\n\n        <ng-template #errorTemplate let-error>\n          <div\n            class="optimistic-callout optimistic-callout--error"\n            data-testid="optimistic-state-toggle-error"\n          >\n            {{ error }}\n          </div>\n        </ng-template>\n\n        <ng-template #valueTemplate let-features>\n          <div class="optimistic-feature-list">\n            @for (feature of features; track feature.id) {\n              <article\n                class="optimistic-feature-row"\n                [class.is-pending]="feature.pending"\n                [attr.data-testid]="\'optimistic-state-toggle-row-\' + feature.id"\n              >\n                <div class="optimistic-feature-row__meta">\n                  <div>\n                    <h4>{{ feature.label }}</h4>\n                    <p>{{ feature.description }}</p>\n                  </div>\n\n                  <span class="optimistic-status-badge">{{\n                    feature.enabled ? \'Enabled\' : \'Disabled\'\n                  }}</span>\n                </div>\n\n                @if (feature.pending) {\n                  <span class="demo-hint-pill">Pending local overlay</span>\n                }\n              </article>\n            }\n          </div>\n        </ng-template>\n      </section>\n\n      <section class="optimistic-surface" data-testid="optimistic-state-toggle-facts-panel">\n        <p class="demo-eyebrow">Conflict policy facts</p>\n        <h3>Visible overlap story</h3>\n\n        <ul class="optimistic-fact-list">\n          <li data-testid="optimistic-state-toggle-pending-count">\n            Pending count: {{ featureToggles.pendingCount() }}\n          </li>\n          <li data-testid="optimistic-state-toggle-queued-count">\n            Queued count: {{ featureToggles.queuedCount() }}\n          </li>\n          <li data-testid="optimistic-state-toggle-overlap-summary">\n            {{ overlapSummary() }}\n          </li>\n        </ul>\n      </section>\n    </div>\n  </article>\n\n  <demo-inspector-panel\n    demoAside\n    panelTestId="optimistic-state-toggle-inspector-panel"\n    snapshotTestId="optimistic-state-toggle-snapshot-json"\n    codeTestId="optimistic-state-toggle-code-sample"\n    title="Live optimistic state and source"\n    summary="The source excerpt comes from the real demo component, so the conflict-policy configuration and rollback wiring stay documentation-grade."\n    [snapshotJson]="snapshotJson()"\n    [docsLinks]="demo.docsLinks"\n    [snippetId]="demo.codeSample.snippetId"\n  />\n</demo-page-layout>',
