        code: '<demo-page-layout testId="optimistic-state-inline-edit-page">\n  <demo-navigation-strip\n    demoNavigation\n    testId="optimistic-state-inline-edit-demo-navigation"\n    [demo]="demo"\n  />\n\n  <article\n    demoIntro\n    class="demo-card demo-card--stack"\n    data-testid="optimistic-state-inline-edit-controls-card"\n  >\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular Optimistic State</p>\n        <h2>Inline edits with queued follow-up saves and canonical server reconciliation.</h2>\n      </div>\n\n      <div class="optimistic-toolbar">\n        <span class="demo-hint-pill" data-testid="optimistic-state-inline-edit-status-pill"\n          >Status: {{ draftEdits.status() }}</span\n        >\n        <span class="demo-hint-pill" data-testid="optimistic-state-inline-edit-policy-pill"\n          >Policy: {{ draftEdits.conflictPolicy() }}</span\n        >\n      </div>\n    </div>\n\n    <p class="demo-card__summary">\n      This route fixes `optimisticState()` to the `queue` policy. A second save for the same draft\n      row waits until the first settles, so queued intent is explicit instead of racing hidden form\n      state.\n    </p>\n\n    <div class="optimistic-controls-grid">\n      <label class="demo-field optimistic-controls-grid__wide">\n        <span>Draft row</span>\n        <select\n          class="demo-select"\n          [ngModel]="selectedRowId()"\n          data-testid="optimistic-state-inline-edit-row-select"\n          (ngModelChange)="updateSelectedRow($event)"\n        >\n          @for (row of draftEdits.value(); track row.id) {\n            <option [value]="row.id">{{ row.id }} · {{ row.owner }}</option>\n          }\n        </select>\n      </label>\n\n      <label class="demo-field optimistic-controls-grid__wide">\n        <span>Draft title</span>\n        <input\n          class="demo-input"\n          [ngModel]="draftTitle()"\n          data-testid="optimistic-state-inline-edit-input"\n          (ngModelChange)="draftTitle.set($event)"\n        />\n      </label>\n\n      <button\n        type="button"\n        class="demo-button"\n        data-testid="optimistic-state-inline-edit-save"\n        (click)="saveDraft()"\n      >\n        Save draft\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="optimistic-state-inline-edit-queue"\n        (click)="queueFollowUpSave()"\n      >\n        Queue follow-up save\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="optimistic-state-inline-edit-fail"\n        (click)="failDraft()"\n      >\n        Force failure\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="optimistic-state-inline-edit-reset"\n        (click)="resetDemo()"\n      >\n        Reset demo\n      </button>\n    </div>\n\n    <demo-status-strip\n      testId="optimistic-state-inline-edit-status-strip"\n      summaryTestId="optimistic-state-inline-edit-summary"\n      urlTestId="optimistic-state-inline-edit-current-url"\n      [summary]="statusSummary()"\n      [currentUrl]="currentUrl()"\n    />\n  </article>\n\n  <article\n    demoPrimary\n    class="demo-card demo-card--stack"\n    data-testid="optimistic-state-inline-edit-render-card"\n  >\n    <div class="optimistic-render-grid">\n      <section class="optimistic-surface" data-testid="optimistic-state-inline-edit-list-panel">\n        <p class="demo-eyebrow">Current optimistic rows</p>\n        <h3>Queued intent becomes visible only after the first save settles</h3>\n\n        <div class="optimistic-row-list">\n          @for (row of draftEdits.value(); track row.id) {\n            <article\n              class="optimistic-row"\n              [class.is-pending]="row.pending"\n              [attr.data-testid]="\'optimistic-state-inline-edit-row-\' + row.id"\n            >\n              <div class="optimistic-row__meta">\n                <div>\n                  <h4>{{ row.title }}</h4>\n                  <p>{{ row.owner }}</p>\n                </div>\n\n                @if (row.pending) {\n                  <span class="demo-hint-pill">Pending save</span>\n                }\n              </div>\n            </article>\n          }\n        </div>\n      </section>\n\n      <section class="optimistic-surface" data-testid="optimistic-state-inline-edit-facts-panel">\n        <p class="demo-eyebrow">Queue facts</p>\n        <h3>One row, explicit overlap behavior</h3>\n\n        @if (draftEdits.isError()) {\n          <div\n            class="optimistic-callout optimistic-callout--error"\n            data-testid="optimistic-state-inline-edit-error"\n          >\n            {{ draftEdits.error() }}\n          </div>\n        }\n\n        <ul class="optimistic-fact-list">\n          <li data-testid="optimistic-state-inline-edit-pending-count">\n            Pending count: {{ draftEdits.pendingCount() }}\n          </li>\n          <li data-testid="optimistic-state-inline-edit-queued-count">\n            Queued count: {{ draftEdits.queuedCount() }}\n          </li>\n          <li data-testid="optimistic-state-inline-edit-queue-summary">\n            {{ queueSummary() }}\n          </li>\n        </ul>\n      </section>\n    </div>\n  </article>\n\n  <demo-inspector-panel\n    demoAside\n    panelTestId="optimistic-state-inline-edit-inspector-panel"\n    snapshotTestId="optimistic-state-inline-edit-snapshot-json"\n    codeTestId="optimistic-state-inline-edit-code-sample"\n    title="Queued optimistic edits and source"\n    summary="The source excerpt comes from the real demo component, so queued same-row saves and reconciliation logic stay documentation-grade."\n    [snapshotJson]="snapshotJson()"\n    [docsLinks]="demo.docsLinks"\n    [snippetId]="demo.codeSample.snippetId"\n  />\n</demo-page-layout>',
