        code: ':host {\n  display: block;\n}\n\n.optimistic-toolbar {\n  display: flex;\n  gap: 0.8rem;\n  align-items: center;\n  flex-wrap: wrap;\n}\n\n.optimistic-controls-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(auto-fit, minmax(13rem, 1fr));\n}\n\n.optimistic-controls-grid__wide {\n  grid-column: span 2;\n}\n\n.optimistic-render-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(auto-fit, minmax(18rem, 1fr));\n}\n\n.optimistic-surface {\n  display: grid;\n  gap: 0.85rem;\n  padding: 1rem;\n  border: 1px solid var(--color-border);\n  border-radius: 1.1rem;\n  background: color-mix(in srgb, var(--color-surface-strong) 84%, white);\n  box-shadow: var(--shadow-soft);\n}\n\n.optimistic-row-list {\n  display: grid;\n  gap: 0.8rem;\n}\n\n.optimistic-row {\n  display: grid;\n  gap: 0.45rem;\n  padding: 0.95rem 1rem;\n  border-radius: 1rem;\n  border: 1px solid var(--color-border);\n  background: color-mix(in srgb, var(--color-surface) 86%, white);\n}\n\n.optimistic-row.is-pending {\n  border-color: rgba(23, 94, 147, 0.24);\n  background: linear-gradient(180deg, rgba(228, 240, 249, 0.96), rgba(217, 233, 246, 0.84));\n}\n\n.optimistic-row__meta {\n  display: flex;\n  gap: 1rem;\n  justify-content: space-between;\n}\n\n.optimistic-row__meta h4,\n.optimistic-row__meta p {\n  margin: 0;\n}\n\n.optimistic-callout {\n  padding: 0.95rem 1rem;\n  border-radius: 1rem;\n  border: 1px solid var(--color-border);\n  box-shadow: var(--shadow-soft);\n}\n\n.optimistic-callout--error {\n  background: linear-gradient(180deg, rgba(255, 232, 232, 0.94), rgba(255, 214, 214, 0.8));\n  border-color: rgba(154, 31, 31, 0.18);\n}\n\n.optimistic-fact-list {\n  display: grid;\n  gap: 0.55rem;\n  margin: 0;\n  padding-left: 1.1rem;\n  color: var(--color-muted);\n}\n\n@media (max-width: 720px) {\n  .optimistic-controls-grid__wide {\n    grid-column: span 1;\n  }\n\n  .optimistic-row__meta {\n    flex-direction: column;\n  }\n}',
